    });
  }, [actionHeight, finalVideoShotIds, pixelsPerSecond, resizeOverrides, rowActionMaps, rowHeight, rows, shotGroups, startLeft]);
  const hideShotGroups = dragSessionRef?.current !== null || hasResizeOverrides;

